import{_ as a,o,c as r,a2 as t}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"CZeroX 应用","description":"","frontmatter":{},"headers":[],"relativePath":"guide/app.md","filePath":"guide/app.md","lastUpdated":1783349713000}'),i={name:"guide/app.md"};function l(n,e,s,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="czerox-应用" tabindex="-1">CZeroX 应用 <a class="header-anchor" href="#czerox-应用" aria-label="Permalink to &quot;CZeroX 应用&quot;">​</a></h1><p><strong>CZeroX</strong> 是 CZero 的原生配套应用，采用 Jetpack Compose 构建，直接读写模块的 <code>config.json</code>。它是模块唯一的图形化配置前端，无需 WebUI。</p><h2 id="下载" tabindex="-1">下载 <a class="header-anchor" href="#下载" aria-label="Permalink to &quot;下载&quot;">​</a></h2><p>在 <a href="https://github.com/Xocio/CZero/releases" target="_blank" rel="noreferrer">Releases</a> 页面下载最新版 CZeroX APK 并安装。</p><h2 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h2><h3 id="主页仪表盘" tabindex="-1">主页仪表盘 <a class="header-anchor" href="#主页仪表盘" aria-label="Permalink to &quot;主页仪表盘&quot;">​</a></h3><ul><li><strong>守护进程状态</strong> —— PID 与内存占用；进程未运行时可一键重启。</li><li><strong>清理统计</strong> —— 今日与累计清理数据（来自 <code>basis.prop</code>）。</li><li><strong>F2FS 状态卡片</strong> —— 实时展示脏段 / 空闲段 / 已用段 / 总段数。</li></ul><h3 id="一键操作" tabindex="-1">一键操作 <a class="header-anchor" href="#一键操作" aria-label="Permalink to &quot;一键操作&quot;">​</a></h3><ul><li>立即清理（运行全部清理任务）</li><li>单应用清理</li><li>后台压制</li><li>F2FS GC（主方案 / 备用方案）</li><li>空文件夹清理</li></ul><p>执行过程可通过通知显示进度与结果。</p><h3 id="设置编辑器" tabindex="-1">设置编辑器 <a class="header-anchor" href="#设置编辑器" aria-label="Permalink to &quot;设置编辑器&quot;">​</a></h3><p>覆盖 <code>config.json</code> 中的每一项：各功能开关、调度间隔与时刻、GC 阈值、时序屏障等。保存后守护进程即时热重载 —— 无需重启。</p><h3 id="规则编辑器" tabindex="-1">规则编辑器 <a class="header-anchor" href="#规则编辑器" aria-label="Permalink to &quot;规则编辑器&quot;">​</a></h3><p>管理黑白名单与自定义路径列表（<code>clean_paths.prop</code>），用于扩展或收窄清理范围。</p><h3 id="回收站" tabindex="-1">回收站 <a class="header-anchor" href="#回收站" aria-label="Permalink to &quot;回收站&quot;">​</a></h3><p>查看清理产生的回收会话（文件数、大小、过期时间），并一键把误删的文件恢复到原位。数据来自 <code>list/customize</code> 的 <code>list</code> / <code>restore</code> 子命令，被清理的文件默认保留 7 天。详见<a href="/guide/features#回收站与恢复">功能详解 · 回收站与恢复</a>。</p><h2 id="语言" tabindex="-1">语言 <a class="header-anchor" href="#语言" aria-label="Permalink to &quot;语言&quot;">​</a></h2><p>CZeroX 支持 <strong>简体中文</strong> 与 <strong>English</strong>，跟随系统或在应用内切换。</p><h2 id="与模块的关系" tabindex="-1">与模块的关系 <a class="header-anchor" href="#与模块的关系" aria-label="Permalink to &quot;与模块的关系&quot;">​</a></h2><p>CZeroX 本身不执行清理，它只负责<strong>读写 <code>config.json</code> 并展示状态</strong>；真正的调度与清理由模块内的 C++ 守护进程完成。因此即使不安装 CZeroX，模块也能按默认配置正常工作 —— 应用的价值在于让配置与查看变得直观。</p>',20)])])}const f=a(i,[["render",l]]);export{u as __pageData,f as default};
